import { writeOutput } from "./codegen";

const DOCS_URL =
  "https://docs.similarweb.com/api-v5/getting-started/authentication";
const PLACEHOLDER_VALUE =
  "CoffeeSafeLocalCoffeeSafeLocalCoffeeSafeLocalCoffeeSa";

function generateTypeScript(): string {
  const lines: string[] = [
    "// Auto-generated from SimilarWeb API docs.",
    `// Source: ${DOCS_URL}`,
    "// Regenerate: cd turbo && pnpm -F @vm0/firewalls-generator generate:similarweb",
    "//",
    "// DO NOT EDIT THIS FILE MANUALLY.",
    "",
    'import type { FirewallConfig } from "../firewall-types";',
    "",
    "export const similarwebFirewall = {",
    '  name: "similarweb",',
    '  description: "SimilarWeb API",',
    "  placeholders: {",
    `    SIMILARWEB_TOKEN: "${PLACEHOLDER_VALUE}",`,
    "  },",
    "  apis: [",
    "    {",
    '      base: "https://api.similarweb.com",',
    "      auth: {",
    "        headers: {",
    '          "api-key": "${{ secrets.SIMILARWEB_TOKEN }}",',
    "        },",
    "      },",
    "      permissions: [],",
    "    },",
    "  ],",
    "} as const satisfies FirewallConfig;",
    "",
  ];
  return lines.join("\n");
}

export async function generate(): Promise<void> {
  console.error("Generating SimilarWeb firewall config...");
  const ts = generateTypeScript();
  writeOutput("similarweb", ts, import.meta.dirname);
}
